#### 方法一：枚举

考虑一个简化问题的求解：在不删除冲突对的情况下，计算不同时包含任何冲突对的合法子数组数目。

对于简化问题，首先枚举子数组的左端点 $i$，然后在不同时包含任何冲突对的条件下，获取子数组的右端点 $j$ 的取值范围。对于冲突对 $\textit{conflictingPairs}[k] = [a_k, b_k]$，假设 $a_k \lt b_k$（如果不满足，则交换二者的位置），有两种情况：

- $a_k \lt i$，那么无论 $j$ 如何取值，都不会同时包含 $a_k$ 和 $b_k$

- $a_k \ge i$，那么 $j < b_k$

根据以上讨论，令 $b_1 = \min_{a_k \ge i}b_k$，我们可以得到 $j$ 的取值范围：

$$
i \le j \lt \min(b_1, n + 1)
$$

因此，左端点为 $i$ 的合法子数组数目为 $\min(n + 1, b_1) - i$。为了快速地计算 $b_1$，我们使用数组 $\textit{bMin}_1$ 和 $\textit{bMin}_2$ 记录所有冲突对 $\textit{conflictingPairs}$ 在同一 $a$ 的最小 $b$ 和次小 $b$ 的值（$a \lt b$），那么 $b_1$ 可以通过计算 $\textit{bMin}_1$ 的后缀最小值来求解。

现在考虑删除恰好一个冲突对后，合法子数组数目的计算。对于左端点为 $i$ 的子数组，它的右端点 $j$ 的取值范围跟 $b_1$ 有关，如果删除的冲突对不涉及 $b_1$，那么左端点为 $i$ 的合法子数组数目不变。

假设 $b_1$ 在 $\textit{bMin}_1$ 的下标为 $i_{b_1}$，即 $\textit{bMin}_1[i_{b_1}] = b_1$，我们使用 $\textit{delCount}[i_{b_1}]$ 记录删除掉 $b_1$ 对应的冲突对后，可以增加的合法子数组的数量。令 $b_2$ 为 $\textit{bMin}_1$ 在下标 $i$ 的后缀次小值，那么删除掉 $b_1$ 后，新的 $b_1^{'} = \min(b_2, \textit{bMin}_2[i_{b_1}])$，增加的合法子数组数目为 $\min(b_1^{'}, n + 1) - \min(b_1, n + 1)$，将它累加到 $\textit{delCount}[i_{b_1}]$ 中。

那么，在恰好删除一个冲突对后，可以得到的最大合法子数组数量等于不删除冲突对的最大合法子数组数量加上删除一个冲突对后增加的合法子数组数量 $\textit{delCount}$ 的最大值。

```C++ [sol1-C++]
class Solution {
public:
    long long maxSubarrays(int n, vector<vector<int>>& conflictingPairs) {
        vector<int> bMin1(n + 1, INT_MAX), bMin2(n + 1, INT_MAX);
        for (const auto& pair : conflictingPairs) {
            int a = min(pair[0], pair[1]), b = max(pair[0], pair[1]);
            if (bMin1[a] > b) {
                bMin2[a] = bMin1[a];
                bMin1[a] = b;
            } else if (bMin2[a] > b) {
                bMin2[a] = b;
            }
        }
        long long res = 0;
        int ib1 = n, b2 = INT_MAX;
        vector<long long> delCount(n + 1, 0);
        for (int i = n; i >= 1; i--) {
            if (bMin1[ib1] > bMin1[i]) {
                b2 = min(b2, bMin1[ib1]);
                ib1 = i;
            } else {
                b2 = min(b2, bMin1[i]);
            }
            res += min(bMin1[ib1], n + 1) - i;
            delCount[ib1] += min(min(b2, bMin2[ib1]), n + 1) - min(bMin1[ib1], n + 1);
        }
        return res + *max_element(delCount.begin(), delCount.end());
    }
};
```

```Go [sol1-Go]
func maxSubarrays(n int, conflictingPairs [][]int) int64 {
    bMin1 := make([]int, n+1)
    bMin2 := make([]int, n+1)
    for i := 0; i <= n; i++ {
        bMin1[i] = math.MaxInt32
        bMin2[i] = math.MaxInt32
    }
    for _, pair := range conflictingPairs {
        a := min(pair[0], pair[1])
        b := max(pair[0], pair[1])
        if bMin1[a] > b {
            bMin2[a] = bMin1[a]
            bMin1[a] = b
        } else if bMin2[a] > b {
            bMin2[a] = b
        }
    }
    res, ib1, b2 := int64(0), n, math.MaxInt32
    delCount := make([]int64, n+1)
    for i := n; i >= 1; i-- {
        if bMin1[ib1] > bMin1[i] {
            b2 = min(b2, bMin1[ib1])
            ib1 = i
        } else {
            b2 = min(b2, bMin1[i])
        }
        res += int64(min(bMin1[ib1], n+1) - i)
        delCount[ib1] += int64(min(min(b2, bMin2[ib1]), n+1) - min(bMin1[ib1], n+1))
    }
    maxVal := int64(0)
    for _, v := range delCount {
        maxVal = max(maxVal, v)
    }
    return res + maxVal
}
```

